CREATE TABLE calibration_policies_v2(policy_id UUID PRIMARY KEY,policy_version TEXT NOT NULL UNIQUE,policy_checksum TEXT NOT NULL CHECK(length(policy_checksum)=64),strategy TEXT NOT NULL,direction TEXT NOT NULL,holding_horizon TEXT NOT NULL,policy JSONB NOT NULL,created_at TIMESTAMP NOT NULL);
CREATE TABLE calibration_runs_v2(run_id UUID PRIMARY KEY,policy_id UUID NOT NULL REFERENCES calibration_policies_v2(policy_id),cutoff_at TIMESTAMP NOT NULL,dataset_checksum TEXT NOT NULL CHECK(length(dataset_checksum)=64),state TEXT NOT NULL CHECK(state IN ('CALIBRATED','INSUFFICIENT_EVIDENCE')),calibration_sample_size INTEGER NOT NULL,effective_sample_size NUMERIC NOT NULL,brier_score NUMERIC,log_loss NUMERIC,expected_calibration_error NUMERIC,maximum_calibration_error NUMERIC,confidence_interval_coverage NUMERIC,abstention_rate NUMERIC,recommendation_coverage NUMERIC,net_expected_value NUMERIC,realized_outcome_rate NUMERIC,return_prediction_low NUMERIC,return_prediction_high NUMERIC,expected_value_low NUMERIC,expected_value_high NUMERIC,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),started_at TIMESTAMP NOT NULL,completed_at TIMESTAMP NOT NULL,UNIQUE(policy_id,cutoff_at,dataset_checksum));
CREATE TABLE calibration_reliability_bins_v2(run_id UUID NOT NULL REFERENCES calibration_runs_v2(run_id),bin_number INTEGER NOT NULL,prediction_low NUMERIC NOT NULL,prediction_high NUMERIC NOT NULL,sample_count INTEGER NOT NULL,mean_uncalibrated_score NUMERIC,calibrated_probability NUMERIC,observed_win_rate NUMERIC,PRIMARY KEY(run_id,bin_number));
CREATE TABLE calibration_dataset_lineage_v2(run_id UUID NOT NULL REFERENCES calibration_runs_v2(run_id),candidate_id UUID NOT NULL REFERENCES opportunity_candidates_v2(candidate_id),outcome_id UUID NOT NULL REFERENCES historical_outcomes_v2(outcome_id),period_name TEXT NOT NULL,included BOOLEAN NOT NULL,exclusion_reason TEXT,observed_at TIMESTAMP NOT NULL,terminal_at TIMESTAMP NOT NULL,PRIMARY KEY(run_id,candidate_id,outcome_id));
CREATE TABLE recommendation_evaluations_v2(evaluation_id UUID PRIMARY KEY,policy_id UUID NOT NULL REFERENCES calibration_policies_v2(policy_id),calibration_run_id UUID REFERENCES calibration_runs_v2(run_id),candidate_id UUID NOT NULL REFERENCES opportunity_candidates_v2(candidate_id),state TEXT NOT NULL,eligible BOOLEAN NOT NULL,calibrated_win_probability NUMERIC,win_probability_low NUMERIC,win_probability_high NUMERIC,conservative_expected_value NUMERIC,uncertainty_tier TEXT,effective_sample_size NUMERIC NOT NULL,calibration_sample_size INTEGER NOT NULL,gates JSONB NOT NULL,reasons JSONB NOT NULL,dataset_lineage_checksum TEXT,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),evaluated_at TIMESTAMP NOT NULL,CHECK((eligible AND state='ELIGIBLE' AND calibrated_win_probability IS NOT NULL AND conservative_expected_value IS NOT NULL) OR (NOT eligible AND state<>'ELIGIBLE')));
CREATE FUNCTION reject_calibration_v2_mutation() RETURNS trigger AS $$ BEGIN RAISE EXCEPTION 'Calibration V2 evidence is immutable'; END; $$ LANGUAGE plpgsql;
CREATE TRIGGER calibration_policies_v2_immutable BEFORE UPDATE OR DELETE ON calibration_policies_v2 FOR EACH ROW EXECUTE FUNCTION reject_calibration_v2_mutation();
CREATE TRIGGER calibration_runs_v2_immutable BEFORE UPDATE OR DELETE ON calibration_runs_v2 FOR EACH ROW EXECUTE FUNCTION reject_calibration_v2_mutation();
CREATE TRIGGER calibration_bins_v2_immutable BEFORE UPDATE OR DELETE ON calibration_reliability_bins_v2 FOR EACH ROW EXECUTE FUNCTION reject_calibration_v2_mutation();
CREATE TRIGGER calibration_lineage_v2_immutable BEFORE UPDATE OR DELETE ON calibration_dataset_lineage_v2 FOR EACH ROW EXECUTE FUNCTION reject_calibration_v2_mutation();
CREATE TRIGGER recommendation_evaluations_v2_immutable BEFORE UPDATE OR DELETE ON recommendation_evaluations_v2 FOR EACH ROW EXECUTE FUNCTION reject_calibration_v2_mutation();
